-- Run after creating a user, replacing the UUID below with auth.users.id.
do $$declare uid uuid := '00000000-0000-0000-0000-000000000000'; cid uuid;begin if exists(select 1 from auth.users where id=uid) then update public.user_settings set business_name='Oak & Brush Decorating',telephone='07123 456789',google_review_link='https://g.page/r/example/review' where user_id=uid;insert into public.customers(user_id,name,mobile,email,address,notes) values(uid,'Sarah Thompson','07700900123','sarah@example.com','14 Meadow Lane, Bristol','Prefers messages after 5pm') returning id into cid;insert into public.quotes(user_id,customer_id,job_description,value_pence,quote_date,status,next_follow_up_date) values(uid,cid,'Paint hall, stairs and landing',185000,current_date-3,'Sent',current_date);end if;end$$;
